queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?chalets a :Chalets .
    ?chalets p:chaletName ?chaletname .
    ?chalets p:pricePerNight ?pricepernight_f .
    FILTER((STR(?pricepernight_f) = "200" || STR(?pricepernight_f) = "200.0"))
    BIND(?chaletname AS ?o0)
  }
  UNION
  {
    ?cabins a :Cabins .
    ?cabins p:cabinName ?cabinname .
    ?cabins p:pricePerNight ?pricepernight_f .
    FILTER((STR(?pricepernight_f) = "200" || STR(?pricepernight_f) = "200.0"))
    BIND(?cabinname AS ?o0)
  }
}

